const numbersToWords=j=>{const F=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(j<0x14)return F[j];if(j<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](j/0xa)]+(j%0xa?'\x20'+F[j%0xa]:'');if(j<0x3e8){const T=Math['floor'](j/0x64),f=j%0x64;return(0x1===T?'εκατό':0x2===T?'διακόσια':0x3===T?'τριακόσια':0x4===T?'τετρακόσια':0x5===T?'πεντακόσια':0x6===T?'εξακόσια':0x7===T?'επτακόσια':0x8===T?'οκτακόσια':0x9===T?'εννιακόσια':'')+(f?'\x20'+numbersToWords(f):'');}return j<0xf4240?numbersToWords(Math['floor'](j/0x3e8))+'\x20χιλιάδες'+(j%0x3e8?'\x20'+numbersToWords(j%0x3e8):''):numbersToWords(Math['floor'](j/0xf4240))+'\x20εκατομμύρια'+(j%0xf4240?'\x20'+numbersToWords(j%0xf4240):'');},numberToText=(j,F='money')=>{const T=Math['floor'](j),f=Math['round'](0x64*(j-T));let M=numbersToWords(T),a=f>0x0?numbersToWords(f):'';switch(F){case'money':return a?M+'\x20ευρώ\x20και\x20'+a+'\x20λεπτά':M+'\x20ευρώ';case'time':return a?M+'\x20ώρες\x20και\x20'+a+'\x20λεπτά':M+'\x20ώρες';default:return a?M+'\x20και\x20'+a:''+M;}};